# Find all spans between quotes
matches = []
for m in re.finditer(r'"(.*?)"', text, flags=re.DOTALL):
    matches.append({
        'span_start': m.start(1),
        'span_end': m.end(1),
        'span_text': m.group(1)
    })
len(matches), matches[:3]

citations = []
for m in matches:
    txt = m['span_text']
    ctype = None
    aya_ref = {"sura_name": "", "sura_number": None, "aya_number": None}
    had_ref = {"collection_name": "", "book_number": None, "hadith_number": None}
    is_valid = True
    corrected = txt
    completely_invalid = False
    # classify
    if 'أَوْحَيْنَا إِلَيْكَ' in txt:
        ctype = 'Aya'
        # The verse is 4:163. The quote has an extra 'و' at start; correct it.
        is_valid = False if txt.startswith('و') else True
        aya_ref = {"sura_name": "النساء", "sura_number": 4, "aya_number": 163}
        corrected = 'إِنَّا أَوْحَيْنَا إِلَيْكَ كَمَا أَوْحَيْنَا إِلَىٰ نُوحٍ وَالنَّبِيِّينَ مِنْ بَعْدِهِ'
    elif 'شِيَعِ الْأَوَّلِينَ' in txt:
        ctype = 'Aya'
        # The correct verse is 15:10 with "ولقد أرسلنا"
        is_valid = False
        aya_ref = {"sura_name": "الحجر", "sura_number": 15, "aya_number": 10}
        corrected = 'وَلَقَدْ أَرْسَلْنَا مِنْ قَبْلِكَ فِي شِيَعِ الْأَوَّلِينَ'
    elif txt.startswith('لا تطروني'):
        ctype = 'Hadeeth'
        # valid hadith; small variant of 'فإنما' vs 'إنما'; we accept and maybe correct to فإنما
        is_valid = True
        had_ref = {"collection_name": "Sahih al-Bukhari", "book_number": 60, "hadith_number": 3445}
        if 'إنما أنا عبد' in txt and 'فإنما أنا عبد' not in txt:
            corrected = txt.replace('إنما أنا عبد', 'فإنما أنا عبد')
    elif txt.startswith('لا تسبوا أصحابي'):
        ctype = 'Hadeeth'
        is_valid = True
        had_ref = {"collection_name": "Sahih al-Bukhari", "book_number": 62, "hadith_number": 3673}
    else:
        ctype = 'Hadeeth'  # default, but mark invalid
        is_valid = False
        completely_invalid = True
        corrected = 'خطأ'
    citations.append({
        "span_start": m['span_start'],
        "span_end": m['span_end'],
        "span_text": txt,
        "citation_type": ctype,
        "is_valid": is_valid,
        "aya_reference": aya_ref if ctype=='Aya' else {},
        "hadeeth_reference": had_ref if ctype=='Hadeeth' else {},
        "corrected_text": corrected,
        "completely_invalid": completely_invalid
    })
len(citations)

output_obj = {"citations": citations}
# Validate structure by printing sample size
len(output_obj["citations"])
